window.__QUIZ_DATA__=[{"id":"theory>Economics>2022>1>a","subject":"Economics","year":"2022","type":"Theory","sub_label":"a","group":"FINAL","topic":"NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME","question":"A hypothetical national income data for a country in particular year is presented below:    ITEM $MILLIONWages and salaries 250Income paid abroad 75Income from self employment 120Stock appreciation 5Interest 10Income received from abroad 50Rent 25Depreciation allowance 3Royalties 2Profits and dividends 35    From the data, answer the following questions.    Calculate the:    Gross Domestic Product (GDP)","images":[],"marking_scheme":"GDP = Wages and salaries + Income from self employment + Rent + Interest + Royalties + Profit & dividend         = 250 + 120 + 25 + 10 + 2 + 35    = $442","marks":"11","difficulty":"3"},{"id":"theory>Economics>2022>1>b","subject":"Economics","year":"2022","type":"Theory","sub_label":"b","group":"FINAL","topic":"NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME","question":"A hypothetical national income data for a country in particular year is presented below:    ITEM $MILLIONWages and salaries 250Income paid abroad 75Income from self employment 120Stock appreciation 5Interest 10Income received from abroad 50Rent 25Depreciation allowance 3Royalties 2Profits and dividends 35    From the data, answer the following questions.    Calculate the:    Gross National Product (GNP)","images":[],"marking_scheme":"GNP = GDP + Net factor income    = 442 + ( 50 - 75)    = 442 - 25    = $417 million","marks":"5","difficulty":"3"},{"id":"theory>Economics>2022>1>c","subject":"Economics","year":"2022","type":"Theory","sub_label":"c","group":"FINAL","topic":"NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME","question":"A hypothetical national income data for a country in particular year is presented below:    ITEM $MILLIONWages and salaries 250Income paid abroad 75Income from self employment 120Stock appreciation 5Interest 10Income received from abroad 50Rent 25Depreciation allowance 3Royalties 2Profits and dividends 35    From the data, answer the following questions.    Calculate the:    Net National Product (NNP)","images":[],"marking_scheme":"NNP = GNP - Depreciation    NNP = 417 - 3    NNP = 414","marks":"4","difficulty":"3"},{"id":"theory>Economics>2022>2>a>i","subject":"Economics","year":"2022","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"AGRICULTURE IN WEST AFRICA : FEATURES","question":"The diagram below shows the effects of the introduction of a subsidy on the production of maize. Study  the diagram and answer the questions that follow.      Identify the curves labelled X,Y,Z","images":["data:image/png;base64,"],"marking_scheme":"- The curve X represent the demand curve    - The curve Y represent the old supply curve    - The curve Z represent the new supply curve","marks":"3","difficulty":"2"},{"id":"theory>Economics>2022>2>a>ii","subject":"Economics","year":"2022","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"AGRICULTURE IN WEST AFRICA : FEATURES","question":"The diagram below shows the effects of the introduction of a subsidy on the production of maize. Study  the diagram and answer the questions that follow.    State the direction of change in price and quantity with the introduction of subsidy","images":["data:image/png;base64,"],"marking_scheme":"Subsidy will shift the supply curve to the right causing price to fall and the quantity demanded to increase","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>2>b>i","subject":"Economics","year":"2022","type":"Theory","sub_label":"i","group":"FINAL","topic":"AGRICULTURE IN WEST AFRICA : FEATURES","question":"The diagram below shows the effects of the introduction of a subsidy on the production of maize. Study  the diagram and answer the questions that follow.    Calculate the total revenue of the producers before the introduction of subsidy","images":["data:image/png;base64,"],"marking_scheme":"Total revenue = Price  x Quantity    Before subsidy, TR = 20 x 15    = $300","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>2>b>ii","subject":"Economics","year":"2022","type":"Theory","sub_label":"ii","group":"FINAL","topic":"AGRICULTURE IN WEST AFRICA : FEATURES","question":"The diagram below shows the effects of the introduction of a subsidy on the production of maize. Study  the diagram and answer the questions that follow.    - Calculate the total revenue of the producers after the introduction of subsidy","images":["data:image/png;base64,"],"marking_scheme":"After subsidy, TR = 10  x 40    = $400","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>2>c","subject":"Economics","year":"2022","type":"Theory","sub_label":"c","group":"FINAL","topic":"AGRICULTURE IN WEST AFRICA : FEATURES","question":"The diagram below shows the effects of the introduction of a subsidy on the production of maize. Study  the diagram and answer the questions that follow.    Calculate the percentage increase or decrease in total revenue of the producers with the introduction of subsidy","images":["data:image/png;base64,"],"marking_scheme":"% increase in revenue =  400 - 300/300  x 100    = 33.33%","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>2>d","subject":"Economics","year":"2022","type":"Theory","sub_label":"d","group":"FINAL","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"The diagram below shows the effects of the introduction of a subsidy on the production of maize. Study  the diagram and answer the questions that follow.    If the quantity demanded of maize increases from 20 to 40 bags as a result of a fall in price from $15 to $10, calculate the price elasticity of demand.","images":["data:image/png;base64,"],"marking_scheme":"e = \u2206Qd/\u2206P   x P/Qd     e = 40 - 20/10 - 15    x 15/20    e = 20/-5   x 15/20     e = - 3 since elasticity is always positive. Therefore, e = 3","marks":"7","difficulty":"3"},{"id":"theory>Economics>2022>2>e","subject":"Economics","year":"2022","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"The diagram below shows the effects of the introduction of a subsidy on the production of maize. Study  the diagram and answer the questions that follow.    State the type of elasticity of demand in 2(d).","images":["data:image/png;base64,"],"marking_scheme":"It is an elastic demand because an increase in quantity demanded leads to a fall in the price of maize.","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>3>a","subject":"Economics","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES","question":"Define the term limited liability","images":[],"marking_scheme":"Limited liability is a business ownership structure that protects shareholders' personal assets from losses and debts. The liability  is limited to the amount invested in the company. Owners and partners are not accountable for the firm's losses and debts.","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>3>b","subject":"Economics","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : PUBLIC CORPORATIONS","question":"Describe four differences between a public joint - stock company and a private joint stock company","images":[],"marking_scheme":"- For a private company,  the minimum membership is 2 shareholder  while the maximum is 50 and for a public,  the minimum is 2 while the maximum has no limits.    - In a private joint stock, the number of directors is atleast 2 while for a pubic, the number of directors is atleast 3.    - There is no need for directors to file anything i.e no restriction on appointment of directors in a private company while in a public joint company, directors must file a consent to act as directors or sign MOA or enter for contract for qualification shares.    - In a private joint stock company, the transfer of shares is restricted while  in a public joint stock company, there is no restriction of shares.","marks":"12","difficulty":"2"},{"id":"theory>Economics>2022>3>c","subject":"Economics","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : SOLE PROPRIETOSHIP","question":"Outline three sources of finance available to sole proprietorship","images":[],"marking_scheme":"-Personal capital:  The sole proprietorship can invest his own savings into his business for expansion. This prevents him from the burden of interest payment and allows him to retain full control over the business.    -  Retained profit: A profitable business generated a positive net income every year. Instead of drawing out large sums of money, a sole trader may opt to retain the earnings for business expansion    - Sale of assets: When a sole trader is short of personal capital and retained earnings and there's a need to further investment in the business,  he may decide to sell some of his assets.","marks":"6","difficulty":"2"},{"id":"theory>Economics>2022>4>a","subject":"Economics","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION","question":"Distinguish between labour force and efficiency of labour","images":[],"marking_scheme":"Labour force can be defined as the total number of persons available to supply the labour for the production of economic goods and services.  In other words, it is the total number of people of working age in a country who are able and willing by law to work.    On the other hand, Efficiency of labour is the ability of labour to increase output without increasing the quantity of labour. Increase in efficiency is usually expressed in terms of increase in output of labour within a shorter period of time without aby fall in the quantity of goods and services produced.","marks":"5","difficulty":"2"},{"id":"theory>Economics>2022>4>b","subject":"Economics","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR","question":"Describe five factors which determine the size of the labour force in a country","images":[],"marking_scheme":"-  Age structure of the population: The structure of a country's population is a significant determination of the size of the labour force. The lower the dependent people, the higher the supply of labour and vice versa. In other word,  the labour force will increase in a country with a greater number of its people between the ages of 18 and 65 years.    - Role of women in te society: In some societies, women are usually prevented from engaging in gainful employment because of religious belief, social and cultural factors and his affects the size of labour force.    - Number of working hours and days: The number of working hours per day and the number of working days in a week or a year also helps to determine the supply of labour.    - The number of disabled: When the number of disabled persons is high especially within the working population,  the supply of labour will be low.    - The number of people who are willing to work: There are certain number of able bodied people who are also between the age bracket of 18 and 65 years but are unwilling to work. If their population is high, it will affect the size of supply of labour.","marks":"15","difficulty":"2"},{"id":"theory>Economics>2022>5>a","subject":"Economics","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"What is a demand schedule?","images":[],"marking_scheme":"Demand schedule is a table which shows the relationship between price and quantity demanded of a consumer.When constructed into a diagram, it become a demand curve.","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>5>b>i","subject":"Economics","year":"2022","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : MEANING AND DETERMINANTS","question":"Explain each of the following terms:    effective demand","images":[],"marking_scheme":"Effective demand refers to the desire, backed up by willingness and ability to buy at a given price.","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>5>b>ii","subject":"Economics","year":"2022","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : TYPES OF DEMAND","question":"Explain each of the following terms:  composite demand","images":[],"marking_scheme":"Demand is said to be composite when it can be put into serveral alternative uses. Hence, each use of the commodity is the rival of the other uses, For example, coal is demanded by railways, factories, households etc.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2022>5>b>iii","subject":"Economics","year":"2022","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : TYPES OF DEMAND","question":"Explain each of the following terms:  derived demand","images":[],"marking_scheme":"It is said to be derived if the demand is for further production. Derived demand occurs as a result of other commodities. For example, demand for labour, demand for money etc.","marks":"2","difficulty":"1"},{"id":"theory>Economics>2022>5>c>i","subject":"Economics","year":"2022","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY","question":"Using appropriate diagrams, explain how a change in the price of  a commodity would influence the demand of its:    substitute","images":["data:image/png;base64,"],"marking_scheme":"In the case of substitute goods, increase in the price of one good results in increase in the demand of its substitute goods e.g tea and cofee are substitute goods. When the price of tea increases, then consumer starts consuming coffee in place of tea. As a result, demand of coffe increases and demand curve of coffee shifts to the right as represented in the diagram below.      When the price decreases, the demand of its substitute goods also falls. As a result, demand of tea decreases and demand curve of tea shifts to the left as represented in the diagram below.","marks":"6","difficulty":"2"},{"id":"theory>Economics>2022>5>c>ii","subject":"Economics","year":"2022","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND","question":"Using appropriate diagrams, explain how a change in the price of  a commodity would influence the demand of its:  complement","images":["data:image/png;base64,"],"marking_scheme":"Complementary goods are purchased jointly such as ink and pens.  An increase in price of complementary goods:  If there is an increase in the price of a good, the demand for another good will decline. So the demand curve shifts parallel to the left i.e from D1D1 to D2D2.       A decrease in  the price of the complementary good:  If there is a decrease in the price of a good, then the demand for another good will increase. So the demand curve shifts parallel to the right, i.e from D1D1 to D2D2.","marks":"6","difficulty":"2"},{"id":"theory>Economics>2022>6>a>i","subject":"Economics","year":"2022","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PUBLIC FINANCE : CLASSIFICATION OF TAX","question":"Explain the following types of taxes:    specific tax","images":[],"marking_scheme":"A specific tax is a tax that is levied on a fixed rate per unit of output i.e it is a fixed tax sum imposed per unit of a commodity.","marks":"3","difficulty":"2"},{"id":"theory>Economics>2022>6>a>ii","subject":"Economics","year":"2022","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PUBLIC FINANCE : CLASSIFICATION OF TAX","question":"Explain the following types of taxes:  value-added tax","images":[],"marking_scheme":"Value added tax are tax levied on businesses at every stage of production and distribution. VAT was introduced in 1994 to replace sales tax and it is a type of indirect taxes.","marks":"3","difficulty":"2"},{"id":"theory>Economics>2022>6>b>i","subject":"Economics","year":"2022","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THEORY OF SUPPLY : ELASTICITY OF SUPPLY","question":"With the aid of diagrams, describe the effects of an indirect tax on a commodity when demand is:    perfectly inelastic","images":["data:image/png;base64,"],"marking_scheme":"The effects of an indirect tax on a commodity when demand is perfectly inelastic is borne by the consumer. In this case, the whole tax burden can easily be shifted to the consumer by the producer or seller in the form of higher prices because increase in price does not bring any change in quantity demand.       From the diagram above, the tax is represented by AB. This tax increases the manufacturer's cost of production. Since the same quantity is purchased irrespective of the price, the manufacturer increase the price of the production from P1 to P2.  The consumer bears the full burden represented by rectangle P1BAP2.","marks":"7","difficulty":"3"},{"id":"theory>Economics>2022>6>b>ii","subject":"Economics","year":"2022","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY","question":"With the aid of diagrams, describe the effects of an indirect tax on a commodity when demand is:  perfectly elastic","images":["data:image/png;base64,"],"marking_scheme":"If the demand for a commodity is perfectly elastic,  the producer or seller will bear the whole burden of taxation. This is so because any attempt to increase price will make the demand for the pproduct fall to zero. The tax burden under this condition cannot be passed to the consumer.      In the diagram above, the tax is represented by EF. Since the tax increases the manufacturer's( seller) cost of production, the quantity supplied decreased from Q1 to Q2. However, the price remains at P since any attempt to increase price will make demand to drop to zero. The maufacturer or seller therefore bears the whole tax burden represented by rectangle PEFG.","marks":"7","difficulty":"3"},{"id":"theory>Economics>2022>7>a>i","subject":"Economics","year":"2022","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC","question":"Distinguish between a:    mortgage bank and a merchant bank","images":[],"marking_scheme":"A mortgage bank is a bank or company which offers a loan with their own funds or from warehouse lenders while a merchant  bank is a financial institution which provides the services of finance, underwriting, offering business loan and advice or consultancy on finance.    A mortgage bank is a bank that provides long term loans to individuals for building houses while a merchant bank provides long term loans to investors for business purpose.","marks":"4","difficulty":"2"},{"id":"theory>Economics>2022>7>a>ii","subject":"Economics","year":"2022","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"FINANCIAL INSTITUTION : COMMERCIAL BANKS","question":"Distinguish between a:  commercial bank and a development bank","images":[],"marking_scheme":"Commercial bank is a bank organized to perform public utility banking services , such as accepting deposits,  lending money etc while development bank refers to a multi-purpose financial undertaking set up to provide financial aid to the industrial and agricultural sector, to encourage development.","marks":"4","difficulty":"2"},{"id":"theory>Economics>2022>7>b","subject":"Economics","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"FINANCIAL INSTITUTION : COMMERCIAL BANKS","question":"Explain any four functions of commercial banks","images":[],"marking_scheme":"- Agency functions: Commercial banks are already agents of the banking system, but they can also be personal agents to their customers. An agent is an individual or institution that carries out activities, in this case, financial operations, on behalf of the principal 9 who is the customer) for a few known commission.    - Credut creation: Commercial banks are perhaps the only financial institutions with this unique function. Commercial banks create credit through accepting deposits and providing loans, pushing money into the economy.    - Transfer of funds: The transfer of funds from a customer's account to another account is another vital  function of banks. Fund transfer is a valid means of paying for transactions, as well as other financial activities. Transfer of funds can be carried out through serveral ways such as drafts, standing orders, cheques,  USSD platforms,and electronic banking.    - Provision of loans: Besides accepting deposits, another function of commercial banks is the provision of loans. The provision of funds to those who require them for transactions is a vital role commercial banks play. Nowadays, customers can now have access to instant loans from commercial banks","marks":"12","difficulty":"2"},{"id":"theory>Economics>2022>8>a","subject":"Economics","year":"2022","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC INTEGRATION : OBJECTIVES, LEVELS OF AND FEATURES","question":"What is economic integration?","images":[],"marking_scheme":"Economic integration is an arrangement among nations that typically includes the reduction or elimination of trade barriers and the coordination of monetary and fiscal policies.","marks":"2","difficulty":"2"},{"id":"theory>Economics>2022>8>b","subject":"Economics","year":"2022","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS","question":"Outline any three short-comings of the Economic Community of West African States (ECOWAS)","images":[],"marking_scheme":"- Political instability: Political instability in member states results in different approach to ECOWAS issues by leaders of member states.    - Inadequate finance: Many member states do not fulfil their financial obligation as at and when due. This is cripping teh effective operation of ECOWAS.    - Colonial linkage: This is another factor affecting ECOWAS. Francophone nations that are members of ECOWAS may not lend their weight to matters of the organisation that will negatively affects france.","marks":"9","difficulty":"3"},{"id":"theory>Economics>2022>8>c","subject":"Economics","year":"2022","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC INTEGRATION : PROBLEMS OF ECONOMIC INTEGRATION IN WEST AFRICA- ECOWAS","question":"Highlight any three achievements of the Economic Community of West African State (ECOWAS)","images":[],"marking_scheme":"- Road construction between big cities: The highways Lagos-Abidjan, Nouakchott-Lagos have made commuting muvch easier that is was before. The road network Elubo-Alflao-Lagos is one of the achievements.    - The relations between the Anglophone and Francophone have been stabilized. It has been done thanks to ECOWAS passport. It has significantly eased the movement of people within those areas.    - Telephone network for the member states: Nowadays, interconnection is available for all countries of the African Union.","marks":"9","difficulty":"2"}];